"""FastAPI application entry point and route definitions."""

from __future__ import annotations

from datetime import datetime, UTC

from fastapi import FastAPI, HTTPException, Query, status

from app.models import Ticket, TicketCreate, TicketListResponse
from app.repository import TicketRepository
from app.service import TicketService

app = FastAPI(title="Demo Issue Tracker API", version="0.1.0")

repository = TicketRepository()
service = TicketService(repository)


@app.get("/health")
def health() -> dict[str, str]:
    """Return a simple health-check response with the current timestamp."""
    return {"status": "ok", "timestamp": datetime.now(UTC).isoformat()}


@app.get("/hello")
def say_hello() -> dict[str, str]:
    """Return a greeting message."""
    return {"message": "Hello, World!"}


@app.get("/joke")
def get_joke() -> dict[str, str]:
    """Return a random programming joke."""
    return {"joke": "Why did the API go to the bar? To get a REST!"}


@app.get("/tickets", response_model=TicketListResponse)
def list_tickets(
    include_archived: bool = Query(default=False),
    search: str | None = Query(default=None),
) -> TicketListResponse:
    """List tickets with optional filtering by archive status and search term."""
    return service.list_tickets(include_archived=include_archived, search=search)


@app.post("/tickets", response_model=Ticket, status_code=status.HTTP_201_CREATED)
def create_ticket(payload: TicketCreate) -> Ticket:
    """Create a new ticket and return the persisted record."""
    return service.create_ticket(payload)


@app.patch("/tickets/{ticket_id}/archive", response_model=Ticket)
def archive_ticket(ticket_id: int) -> Ticket:
    """Archive a ticket by ID. Returns 404 if the ticket does not exist."""
    archived = service.archive_ticket(ticket_id)
    if archived is None:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Ticket not found")
    return archived
"""Integration tests for the Issue Tracker API endpoints."""

from pathlib import Path
import sys

sys.path.insert(0, str(Path(__file__).resolve().parents[1]))

from fastapi.testclient import TestClient

from app.main import app

client = TestClient(app)


def test_healthcheck() -> None:
    response = client.get("/health")

    assert response.status_code == 200
    assert response.json() == {"status": "ok"}


def test_say_hello() -> None:
    response = client.get("/hello")

    assert response.status_code == 200
    assert response.json() == {"message": "Hello, World!"}


def test_get_joke() -> None:
    response = client.get("/joke")

    assert response.status_code == 200
    assert "joke" in response.json()


def test_create_ticket_returns_created_record() -> None:
    response = client.post(
        "/tickets",
        json={
            "title": "Broken mobile nav",
            "description": "Nav drawer overlays the footer on narrow screens.",
            "customer_email": "ops@example.com",
            "priority": "high",
        },
    )

    assert response.status_code == 201
    body = response.json()
    assert body["title"] == "Broken mobile nav"
    assert body["priority"] == "high"


def test_list_tickets_excludes_archived_by_default() -> None:
    response = client.get("/tickets")

    assert response.status_code == 200
    body = response.json()
    assert all(item["archived"] is False for item in body["items"])


def test_list_tickets_includes_archived_when_requested() -> None:
    response = client.get("/tickets", params={"include_archived": True})

    assert response.status_code == 200
    body = response.json()
    archived_items = [item for item in body["items"] if item["archived"]]
    assert len(archived_items) >= 1


def test_list_tickets_supports_search() -> None:
    response = client.get("/tickets", params={"search": "csv"})

    assert response.status_code == 200
    body = response.json()
    assert body["total"] == 1
    assert body["items"][0]["title"] == "Exported CSV omits assignee"


def test_search_excludes_archived_by_default() -> None:
    response = client.get("/tickets", params={"search": "webhook"})

    assert response.status_code == 200
    body = response.json()
    assert body["total"] == 0


def test_search_includes_archived_when_requested() -> None:
    response = client.get("/tickets", params={"search": "webhook", "include_archived": True})

    assert response.status_code == 200
    body = response.json()
    assert body["total"] == 1
    assert body["items"][0]["archived"] is True
"""Business logic layer for ticket operations."""

from __future__ import annotations

from app.models import Ticket, TicketCreate, TicketListResponse
from app.repository import TicketRepository


class TicketService:
    """Orchestrates ticket operations between routes and the repository."""

    def __init__(self, repository: TicketRepository) -> None:
        self._repository = repository

    def list_tickets(self, *, include_archived: bool = False, search: str | None = None) -> TicketListResponse:
        """Return tickets filtered by archive status and optional search term."""
        tickets = self._repository.list_tickets()

        if search:
            lowered = search.lower()
            tickets = [
                ticket
                for ticket in tickets
                if lowered in ticket.title.lower() or lowered in ticket.description.lower()
            ]

        if not include_archived:
            tickets = [t for t in tickets if not t.archived]

        return TicketListResponse(items=tickets, total=len(tickets))

    def create_ticket(self, payload: TicketCreate) -> Ticket:
        """Validate and persist a new ticket from the given payload."""
        ticket = Ticket(
            id=0,
            title=payload.title.strip(),
            description=payload.description.strip(),
            customer_email=payload.customer_email.strip(),
            priority=payload.priority,
        )
        return self._repository.create_ticket(ticket)

    def archive_ticket(self, ticket_id: int) -> Ticket | None:
        """Archive a ticket by ID. Returns the updated ticket or None."""
        return self._repository.archive_ticket(ticket_id)
"""In-memory ticket repository providing CRUD persistence."""

from __future__ import annotations

from app.models import Ticket, TicketPriority, TicketStatus


class TicketRepository:
    """Stores tickets in memory with seed data for demonstration purposes."""
    def __init__(self) -> None:
        self._tickets: list[Ticket] = [
            Ticket(
                id=1,
                title="Checkout button fails on Safari",
                description="Customers report the purchase CTA does nothing on Safari 17.",
                customer_email="ops@northwind.example",
                priority=TicketPriority.high,
                status=TicketStatus.investigating,
            ),
            Ticket(
                id=2,
                title="Exported CSV omits assignee",
                description="Analytics exports should include the current owner column.",
                customer_email="bi@acme.example",
                priority=TicketPriority.medium,
                status=TicketStatus.open,
            ),
            Ticket(
                id=3,
                title="Password reset email arrives twice",
                description="Duplicate notifications are confusing support contacts.",
                customer_email="support@globex.example",
                priority=TicketPriority.medium,
                status=TicketStatus.open,
            ),
            Ticket(
                id=4,
                title="Deprecated webhook endpoint still listed in docs",
                description="Archive this issue after the docs refresh lands.",
                customer_email="docs@initech.example",
                priority=TicketPriority.low,
                status=TicketStatus.archived,
            ),
        ]
        self._next_id = 5

    def list_tickets(self) -> list[Ticket]:
        """Return defensive copies of all stored tickets."""
        return [ticket.model_copy() for ticket in self._tickets]

    def create_ticket(self, ticket: Ticket) -> Ticket:
        """Persist a new ticket, assigning a unique ID."""
        created = ticket.model_copy(update={"id": self._next_id})
        self._next_id += 1
        self._tickets.append(created)
        return created.model_copy()

    def _get_ticket(self, ticket_id: int) -> Ticket | None:
        """Look up a ticket by ID. Returns the live reference or None."""
        for ticket in self._tickets:
            if ticket.id == ticket_id:
                return ticket
        return None

    def get_ticket(self, ticket_id: int) -> Ticket | None:
        """Look up a ticket by ID. Returns a defensive copy or None."""
        ticket = self._get_ticket(ticket_id)
        return ticket.model_copy() if ticket is not None else None

    def archive_ticket(self, ticket_id: int) -> Ticket | None:
        """Mark a ticket as archived. Returns a copy or None if not found."""
        ticket = self._get_ticket(ticket_id)
        if ticket is None:
            return None
        ticket.status = TicketStatus.archived
        return ticket.model_copy()

